  /// Get translation for [key] in [lang]. Falls back to English if not found.
  static String t(String key, String lang) =>
      _s[key]?[lang] ?? _s[key]?['en'] ?? key;

  /// Greeting based on current hour of day.
  static String greeting(String lang) {
    final h = DateTime.now().hour;
    if (h < 12) return t('greet_morning', lang);
    if (h < 17) return t('greet_afternoon', lang);
    return t('greet_evening', lang);
  }
}
